type SnapshotCache[K comparable] struct {
    mu sync.RWMutex

    logger *zap.Logger

    fixed map[string]K
    extra *lru.Cache[string, K]

    store map[K]*Snapshot
}

// Read operation with RLock
func (c *SnapshotCache[K]) Get(ref string) (s *Snapshot, ok bool) {
    c.mu.RLock()
    defer c.mu.RUnlock()

    k, ok := c.fixed[ref]
    if ok {
        s, ok = c.store[k]
        return
    }

    k, ok = c.extra.Get(ref)
    if !ok {
        return s, ok
    }

    s, ok = c.store[k]
    return
}

// Write operation with Lock
func (c *SnapshotCache[K]) AddOrBuild(ctx context.Context, ref string, k K, build CacheBuildFunc[K]) (s *Snapshot, err error) {
    s, ok := c.getByRefAndKey(ref, k)
    if ok {
        return s, nil
    }

    if s == nil {
        s, err = build(ctx, k)
        if err != nil {
            return s, err
        }
    }

    c.mu.Lock()
    defer c.mu.Unlock()

    // Update operations...
    c.store[k] = s
    return s, nil
}
```

